import{_ as e,o,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const h=JSON.parse('{"title":"危机应对","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-scene/危机应对.md","filePath":"05_quotes/by-scene/危机应对.md"}'),c={name:"05_quotes/by-scene/危机应对.md"};function l(u,t,n,s,q,_){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="危机应对" tabindex="-1">危机应对 <a class="header-anchor" href="#危机应对" aria-label="Permalink to &quot;危机应对&quot;">​</a></h1><blockquote><p>&quot;当潮水退去，才知道谁在裸泳。2008年危机是检验企业真正质量的时刻。&quot;——巴菲特</p></blockquote><hr><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;在2008年9月的混乱时期，我写了一篇文章，告诉美国投资者：买入美国股票。现在看起来是显而易见的建议，但在当时需要极大的勇气。&quot;</p></blockquote><blockquote><p>&quot;恐惧是会传染的。金融系统崩溃往往不是因为基本面有多差，而是因为恐惧本身。&quot;</p></blockquote><blockquote><p>&quot;我们不预测危机，我们为危机做准备。我们的做法是：保持充足的资本，不使用过高杠杆，确保在最坏情况下也能生存。&quot;</p></blockquote><blockquote><p>&quot;潮水退去时，我们手里还有资金，可以买到打折的资产。这就是不亏钱的意义——在危机中，你反而变得更有购买力。&quot;</p></blockquote><blockquote><p>&quot;1974年、1987年、2001年、2008年——每一次危机都有人离开市场，每一次危机也都是最好的买入时机。历史一再重复。&quot;</p></blockquote><hr><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><p><a href="/02_concepts/risk.html">风险</a> · <a href="/02_concepts/contrarian.html">逆向思维</a> · <a href="/02_concepts/safety-margin.html">安全边际</a> · <a href="/02_concepts/long-term.html">长期主义</a></p>',12)])])}const i=e(c,[["render",l]]);export{h as __pageData,i as default};
